<template>
  <div class="section section-white">
    <el-form
      ref="form"
      :label-position="'left'"
      :model="form"
      :rules="rules"
      label-width="160px"
    >
      <div class="section-body">
        <el-form-item
          label="預約模式設置"
          prop="modelSetting"
        >
          <el-radio-group v-model="form.reservationMode">
            <el-radio
              v-for="item in reservationModes"
              :key="item.value"
              :label="item.value"
            >
              {{
                item.label
              }}
            </el-radio>
          </el-radio-group>
        </el-form-item>
        <el-form-item
          label="預約時間間隔"
          prop="interval"
        >
          <el-select v-model="form.interval">
            <el-option
              v-for="item in timeIntervals"
              :key="item.value"
              :label="item.label"
              :value="item.value"
            >
              {{ item.label }}
            </el-option>
          </el-select>
        </el-form-item>
        <el-form-item
          label="資源位名稱"
          prop="resourceName"
        >
          <el-input
            v-model="form.resourceName"
            placeholder="計師"
            style="width: 240px"
          />
        </el-form-item>
        <el-form-item
          label="預約區間"
          prop="maxLimitDay"
        >
          最多提前 <el-input
            v-model="form.maxLimitDay"
            style="width: 80px"
          /> 天可預約
        </el-form-item>
        <el-form-item
          label=""
          prop="minLimitHour"
        >
          最少提前 <el-input
            v-model="form.minLimitHour"
            style="width: 80px"
          /> 分鍾可預約
        </el-form-item>
        <el-form-item
          label="取消預約條件"
          prop="cancelMinute"
        >
          到店前 <el-input
            v-model="form.cancelMinute"
            style="width: 80px"
          /> 分鍾可取消預約
          (必須大於最小預約區間)
        </el-form-item>
        <el-form-item
          label="預約條件"
          prop="condition"
        >
          <el-select v-model="form.condition">
            <el-option
              v-for="item in conditions"
              :key="item.value"
              :label="item.label"
              :value="item.value"
            />
          </el-select>
        </el-form-item>
        <el-form-item
          label="預約短信提醒"
          prop="sms_delay"
        >
          提前 <el-input
            v-model="form.sms_delay"
            style="width: 80px"
          /> 小時發送短信提醒
        </el-form-item>
        <el-form-item
          label="預約限制"
          prop="limitType"
        >
          <el-radio-group
            v-model="form.limitType"
            @change="limitChange"
          >
            <el-radio
              v-for="item in limitType"
              :key="item.value"
              :label="item.value"
            >
              {{
                item.label
              }}
            </el-radio>
          </el-radio-group>
          <br>
          <span v-if="form.limitType == 'limit_days'">
            <el-input
              v-model="form.limit"
              style="width: 80px"
            />天內可預約1次(從預約日開始算)
          </span>
          <span v-if="form.limitType == 'limit_nums'">
            1天內可預約 <el-input
              v-model="form.limit"
              style="width: 80px"
            />次
          </span>
        </el-form-item>
      </div>
      <div class="section-footer with-border content-center">
        <el-button
          type="primary"
          @click="save"
        >
          儲存
        </el-button>
      </div>
    </el-form>
  </div>
</template>
<script>
import { getSetting, saveSetting } from '../../../../api/reservation'
export default {
  data () {
    var modelChecked = (rule, val, callback) => {
      if (val.length <= 0) {
        return callback(new Error('請選擇預約模式'))
      }
      callback()
    }
    var limitTypeChecked = (rule, value, callback) => {
      let reg = /^\d*$/
      let limit = this.form.limit
      if (value === 'limit_nums') {
        if (!reg.test(limit)) {
          callback(new Error('預約次數限制必須是數字'))
        } else {
          console.log()
          callback()
        }
      } else if (value === 'limit_days') {
        if (!reg.test(limit)) {
          callback(new Error('預約天數限制必須是數字'))
        } else {
          callback()
        }
      }
    }
    var maxLimitChecked = (rule, value, callback) => {
      let reg = /^\d*$/
      if (!reg.test(value)) {
        callback(new Error('最多提前天數必須為整數'))
      } else {
        callback()
      }
    }
    var minLimitChecked = (rule, value, callback) => {
      let reg = /^\d*$/
      if (!reg.test(value)) {
        callback(new Error('最少提前分鍾數必須為整數'))
      } else {
        callback()
      }
    }
    var smsDelayChecked = (rule, value, callback) => {
      let reg = /^\d*$/
      if (!reg.test(value)) {
        callback(new Error('預約短信通知提醒必須為整數'))
      } else {
        callback()
      }
    }
    var cancelMinuteChecked = (rule, value, callback) => {
      let reg = /^\d*$/
      if (!reg.test(value)) {
        callback(new Error('取消預約條件必須為整數'))
      } else {
        callback()
      }
    }
    return {
      timeIntervals: [
        { value: 15, label: '15分鍾' },
        { value: 30, label: '30分鍾' },
        { value: 60, label: '60分鍾' },
        { value: 90, label: '90分鍾' }
      ],
      conditions: [{ value: 1, label: '免費預約' }],
      reservationModes: [
        { value: 1, label: '門店＋時間+資源位＋服務項目' }
        //{ value: 2, label: '門店＋時間＋服務項目'}
      ],
      form: {
        reservationMode: 1,
        interval: 30,
        maxLimitDay: 10,
        minLimitHour: 30,
        condition: 1,
        resourceName: '資源位',
        cancelMinute: 60,
        limitType: 'not_open',
        sms_delay: 1,
        limit: 1
      },
      rules: {
        modelSetting: [{ required: true, validator: modelChecked, trigger: 'blur' }],
        interval: [{ required: true, message: '預約時間間隔不能為空', trigger: 'blur' }],
        resourceName: [{ required: true, message: '資源位名稱不能為空', trigger: 'blur' }],
        maxLimitDay: [{ required: true, validator: maxLimitChecked, trigger: 'blur' }],
        minLimitHour: [{ required: true, validator: minLimitChecked, trigger: 'blur' }],
        cancelMinute: [{ required: true, validator: cancelMinuteChecked, trigger: 'blur' }],
        condition: [{ required: true, message: '預約條件不能為空', trigger: 'blur' }],
        sms_delay: [{ required: true, validator: smsDelayChecked, trigger: 'blur' }],
        limitType: [{ required: true, validator: limitTypeChecked, trigger: 'blur' }]
      },
      limitType: [
        { value: 'not_open', label: '不開啟限制' },
        { value: 'limit_days', label: '天數限制' },
        { value: 'limit_nums', label: '次數限制' }
      ]
    }
  },
  mounted () {
    this.getData()
  },
  methods: {
    save () {
      saveSetting(this.form).then((res) => {
        if (res.data.data) {
          this.$message({
            type: 'success',
            message: '儲存預約配置成功'
          })
        }
        this.getData()
      })
    },
    getData () {
      this.loading = true
      getSetting().then((res) => {
        if (res.data.data) {
          var data = res.data.data
          this.form.reservationMode = data.reservationMode
          this.form.maxLimitDay = data.maxLimitDay
          this.form.minLimitHour = data.minLimitHour
          this.form.condition = data.reservationCondition
          this.form.resourceName = data.resourceName
          this.form.interval = data.timeInterval
          this.form.cancelMinute = data.cancelMinute
          this.form.sms_delay = data.smsDelay ? data.smsDelay : 1
          if (data.limitType) {
            this.form.limitType = data.limitType
          } else {
            this.form.limitType = 'not_open'
          }
          if (data.limit) {
            this.form.limit = data.limit
          } else {
            this.form.limit = 1
          }
        }
        console.log(this.form)
        this.loading = false
      })
    },
    limitChange () {
      this.form.limit = 0
    }
  }
}
</script>
